"use strict";const statusEl=document.getElementById("status");function setStatus(e){statusEl.textContent=e}document.getElementById("export").addEventListener("click",()=>{chrome.runtime.sendMessage({type:"EXPORT_STORAGE"},e=>{const t=JSON.stringify(e,null,2),n=(new Date).toISOString().slice(0,10),s=document.createElement("a");s.href=`data:application/json;charset=utf-8,${encodeURIComponent(t)}`,s.download=`x-image-sorter-backup-${n}.json`,s.click(),setStatus("エクスポートしました")})}),document.getElementById("import-btn").addEventListener("click",()=>{document.getElementById("import-file").click()}),document.getElementById("import-file").addEventListener("change",e=>{const t=e.target.files?.[0];if(!t)return;const n=new FileReader;n.onload=()=>{try{const e=JSON.parse(n.result);if("object"!=typeof e||null===e||Array.isArray(e))throw new Error;chrome.runtime.sendMessage({type:"IMPORT_STORAGE",data:e},()=>{setStatus("インポートしました")})}catch{setStatus("ファイルが不正です")}},n.readAsText(t)}),document.getElementById("rebuild").addEventListener("click",()=>{chrome.runtime.sendMessage({type:"REBUILD_PROFILES"},()=>{setStatus("再生成しました")})});